import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Progress } from "@/components/ui/progress";
import { Badge } from "@/components/ui/badge";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { Shield, Info, CheckCircle2, AlertTriangle } from "lucide-react";
import { useCountUp } from "@/hooks/useCountUp";
import type { TransparentATSScore } from "@/lib/engines/ats-scoring-engine";

interface ATSScoreCardProps {
  score: TransparentATSScore | null;
}

const getScoreColor = (score: number) => {
  if (score >= 80) return "text-green-500";
  if (score >= 60) return "text-blue-500";
  if (score >= 40) return "text-yellow-500";
  return "text-red-500";
};

export function ATSScoreCard({ score }: ATSScoreCardProps) {
  // Handle loading/null state
  if (!score) return null;

  const animatedScore = useCountUp(score.overall, 1400);

  // Map factors to display format
  // We dynamically render whatever factors are present in the score
  const displayFactors = [
    { key: 'keywordMatch', label: 'Keyword Match', icon: CheckCircle2 },
    { key: 'skillDensity', label: 'Skill Density', icon: Shield },
    { key: 'sectionCompleteness', label: 'Sections', icon: Info },
    { key: 'actionVerbStrength', label: 'Action Verbs', icon: CheckCircle2 },
    { key: 'quantificationPresence', label: 'Quantification', icon: Shield },
    { key: 'projectQuality', label: 'Project Quality', icon: Shield },
    { key: 'experienceDepth', label: 'Experience', icon: Shield },
    { key: 'leadership', label: 'Leadership', icon: Shield },
  ].map(def => {
    // @ts-ignore - Dynamic access to factors
    const factor = score.factors[def.key];
    return factor ? { ...def, ...factor } : null;
  }).filter(Boolean); // Remove nulls (factors not applicable to this stage)

  return (
    <Card className="h-full border-l-4 border-l-primary">
      <CardHeader className="pb-2">
        <div className="flex justify-between items-start">
          <div>
            <CardTitle className="flex items-center gap-2 text-lg">
              <Shield className="h-5 w-5 text-primary" />
              Keyword Coverage Score
            </CardTitle>
            <CardDescription className="text-xs mt-1">
              Calibrated for <strong>{score.careerStage || 'General'}</strong> Level
            </CardDescription>
          </div>
          {score.stageAdjusted && (
            <Badge variant="secondary" className="text-[10px]">
              Stage Adjusted
            </Badge>
          )}
        </div>
      </CardHeader>

      <CardContent>
        <div className="flex items-center gap-6 mb-6">
          {/* Score Circle */}
          <div className="relative flex items-center justify-center shrink-0">
            <svg className="w-24 h-24 -rotate-90" viewBox="0 0 128 128">
              <circle cx="64" cy="64" r="56" fill="none" stroke="currentColor" strokeOpacity="0.1" strokeWidth="8" />
              <circle
                cx="64"
                cy="64"
                r="56"
                fill="none"
                stroke="currentColor"
                strokeWidth="8"
                strokeDasharray={`${(animatedScore / 100) * 352} 352`}
                strokeLinecap="round"
                className={`transition-all duration-1000 ease-out ${getScoreColor(score.overall)}`}
              />
            </svg>
            <div className="absolute text-center">
              <span className={`text-2xl font-bold ${getScoreColor(score.overall)}`}>
                {animatedScore}
              </span>
              <span className="block text-[10px] text-muted-foreground">/100</span>
            </div>
          </div>

          {/* Factor List */}
          <div className="flex-1 space-y-3">
            {displayFactors.map((factor: { key: string; label: string; score: number; computation: string; weight: number }) => (
              <div key={factor.key}>
                <div className="flex justify-between text-xs mb-1">
                  <div className="flex items-center gap-1.5">
                    <span className="font-medium text-muted-foreground">{factor.label}</span>
                    <TooltipProvider>
                      <Tooltip>
                        <TooltipTrigger>
                          <Info className="w-3 h-3 text-muted-foreground/50" />
                        </TooltipTrigger>
                        <TooltipContent>
                          <p className="font-semibold">{factor.computation}</p>
                          <p className="text-xs text-muted-foreground mt-1">Weight: {factor.weight}%</p>
                        </TooltipContent>
                      </Tooltip>
                    </TooltipProvider>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="font-bold">{factor.score}</span>
                    <span className="text-[10px] text-muted-foreground">({factor.weight}%)</span>
                  </div>
                </div>
                <Progress value={factor.score} className="h-1.5" />
              </div>
            ))}
          </div>
        </div>

        {/* Disclaimer/Insight */}
        <div className="bg-muted/50 rounded-lg p-3 flex gap-3 text-xs text-muted-foreground">
          <AlertTriangle className="w-4 h-4 shrink-0 text-amber-500" />
          <p>{score.disclaimer}</p>
        </div>
      </CardContent>
    </Card>
  );
}

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  ResponsiveContainer,
  Cell,
  Tooltip as RechartsTooltip,
} from "recharts";
import { Globe, Info, GitFork, Star, BookOpen } from "lucide-react";
import { useCountUp } from "@/hooks/useCountUp";
import type { PortfolioAnalysis } from "@/lib/integrations/githubClient";

interface PortfolioAnalyzerProps {
  data: PortfolioAnalysis | null;
}

export function PortfolioAnalyzer({ data }: PortfolioAnalyzerProps) {
  if (!data) return null;

  const animatedRating = useCountUp(data.portfolioScore, 1200);

  const chartData = [
    { name: "Activity", value: data.insights.activityScore, color: "hsl(var(--chart-1))" },
    { name: "Quality", value: data.insights.qualityScore, color: "hsl(var(--chart-2))" },
    { name: "Diversity", value: data.insights.diversityScore, color: "hsl(var(--chart-3))" },
    { name: "Docs", value: data.insights.documentationScore, color: "hsl(var(--chart-4))" },
    { name: "Consistency", value: data.insights.consistencyScore, color: "hsl(var(--chart-5))" },
  ];

  return (
    <Card className="h-full">
      <CardHeader>
        <div className="flex justify-between items-start">
          <div>
            <CardTitle className="flex items-center gap-2">
              <Globe className="h-5 w-5 text-primary" />
              Portfolio Strength
            </CardTitle>
            <CardDescription className="mt-1">
              Analysis of {data.repositoryMetrics.totalRepos} repositories and {data.repositoryMetrics.totalStars} stars
            </CardDescription>
          </div>
          <div className="text-right">
            <span className="text-3xl font-bold text-primary">{animatedRating}</span>
            <span className="text-muted-foreground text-sm">/100</span>
          </div>
        </div>
      </CardHeader>
      <CardContent>
        {/* Metric Chart */}
        <div className="h-[180px] mb-6">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} layout="vertical" margin={{ left: 0, right: 30 }}>
              <XAxis type="number" domain={[0, 100]} hide />
              <YAxis
                type="category"
                dataKey="name"
                tick={{ fontSize: 12, fill: "hsl(var(--muted-foreground))" }}
                width={80}
                axisLine={false}
                tickLine={false}
              />
              <RechartsTooltip
                cursor={{ fill: 'transparent' }}
                content={({ active, payload }) => {
                  if (active && payload && payload.length) {
                    return (
                      <div className="bg-popover border text-popover-foreground px-3 py-2 rounded-lg shadow-md text-xs">
                        <span className="font-semibold">{payload[0].payload.name}: </span>
                        {payload[0].value}/100
                      </div>
                    );
                  }
                  return null;
                }}
              />
              <Bar dataKey="value" radius={[0, 4, 4, 0]} barSize={20} background={{ fill: 'hsl(var(--muted))', radius: [0, 4, 4, 0] }}>
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Top Projects */}
        <div>
          <h4 className="font-semibold text-sm mb-3">Top Projects</h4>
          <div className="space-y-3">
            {data.topProjects.slice(0, 3).map((repo) => (
              <div key={repo.name} className="flex items-center justify-between p-2 bg-muted/30 rounded-lg border">
                <div className="overflow-hidden">
                  <div className="font-medium text-sm truncate" title={repo.name}>
                    {repo.name}
                  </div>
                  <div className="text-xs text-muted-foreground flex gap-2">
                    <span className="flex items-center gap-0.5"><Star className="w-3 h-3" /> {repo.stars}</span>
                    <span className="flex items-center gap-0.5"><GitFork className="w-3 h-3" /> {repo.forks}</span>
                    {repo.language && <span>• {repo.language}</span>}
                  </div>
                </div>
                {repo.hasReadme && (
                  <TooltipProvider>
                    <Tooltip>
                      <TooltipTrigger>
                        <BookOpen className="w-4 h-4 text-green-500" />
                      </TooltipTrigger>
                      <TooltipContent>
                        Has README ({repo.readmeLength} chars)
                      </TooltipContent>
                    </Tooltip>
                  </TooltipProvider>
                )}
              </div>
            ))}
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

/**
 * Traceability Accordion Component
 * 
 * Reusable UI component for displaying "How was this calculated?" 
 * explanations with inputs, weights, and computation formulas.
 */

import {
    Accordion,
    AccordionContent,
    AccordionItem,
    AccordionTrigger,
} from "@/components/ui/accordion";
import { Badge } from "@/components/ui/badge";
import { Info } from "lucide-react";

interface TraceabilityAccordionProps {
    title: string;
    score: number;
    inputData: Record<string, any>;
    weights?: Record<string, number>;
    computation: string;
    result: number;
}

export function TraceabilityAccordion({
    title,
    score,
    inputData,
    weights,
    computation,
    result,
}: TraceabilityAccordionProps) {
    return (
        <Accordion type="single" collapsible className="w-full">
            <AccordionItem value="traceability" className="border-none">
                <AccordionTrigger className="text-sm text-muted-foreground hover:text-foreground">
                    <div className="flex items-center gap-2">
                        <Info className="h-4 w-4" />
                        <span>How was this calculated?</span>
                    </div>
                </AccordionTrigger>
                <AccordionContent>
                    <div className="space-y-4 pt-2">
                        {/* Input Data */}
                        <div>
                            <h4 className="font-semibold text-sm mb-2">Input Data</h4>
                            <div className="bg-muted/50 rounded-md p-3 space-y-1.5">
                                {Object.entries(inputData).map(([key, value]) => (
                                    <div key={key} className="flex justify-between text-xs">
                                        <span className="text-muted-foreground">
                                            {formatKey(key)}:
                                        </span>
                                        <span className="font-mono">{formatValue(value)}</span>
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Weights (if provided) */}
                        {weights && Object.keys(weights).length > 0 && (
                            <div>
                                <h4 className="font-semibold text-sm mb-2">Weights Applied</h4>
                                <div className="flex flex-wrap gap-2">
                                    {Object.entries(weights).map(([factor, weight]) => (
                                        <Badge key={factor} variant="outline" className="text-xs">
                                            {formatKey(factor)}: {weight}%
                                        </Badge>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Computation Formula */}
                        <div>
                            <h4 className="font-semibold text-sm mb-2">Computation</h4>
                            <div className="bg-muted/50 rounded-md p-3">
                                <code className="text-xs text-muted-foreground whitespace-pre-wrap">
                                    {computation}
                                </code>
                            </div>
                        </div>

                        {/* Final Result */}
                        <div className="flex items-center justify-between pt-2 border-t">
                            <span className="font-semibold text-sm">Final {title}</span>
                            <Badge variant="default" className="text-base">
                                {result}
                            </Badge>
                        </div>
                    </div>
                </AccordionContent>
            </AccordionItem>
        </Accordion>
    );
}

/**
 * Format object key for display
 */
function formatKey(key: string): string {
    return key
        .replace(/([A-Z])/g, " $1")
        .replace(/^./, (str) => str.toUpperCase())
        .trim();
}

/**
 * Format value for display
 */
function formatValue(value: unknown): string {
    if (Array.isArray(value)) {
        return value.length > 3
            ? `${value.slice(0, 3).join(", ")}... (${value.length} total)`
            : value.join(", ");
    }
    if (typeof value === "object" && value !== null) {
        return JSON.stringify(value, null, 2);
    }
    return String(value);
}

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default: "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary: "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive: "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return <div className={cn(badgeVariants({ variant }), className)} {...props} />;
}

export { Badge, badgeVariants };

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive: "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline: "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return <Comp className={cn(buttonVariants({ variant, size, className }))} ref={ref} {...props} />;
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

