/**
 * Resume Section Detector
 * Uses NLP and pattern matching to detect resume sections
 */

export interface DetectedSection {
    name: string;
    content: string;
    startIndex: number;
    endIndex: number;
    confidence: number; // 0-100
    detectionMethod: 'heading' | 'regex' | 'semantic';
}

export interface SectionDetectionResult {
    sections: { [sectionName: string]: DetectedSection };
    detectedSectionNames: string[];
    completenessScore: number;
    warnings: string[];
}

// Common section headers and their variations
const SECTION_PATTERNS = {
    name: {
        keywords: ['name', 'full name'],
        regex: /^[\s]*([A-Z][a-z]+\s+){1,3}[A-Z][a-z]+[\s]*$/m,
        priority: 1,
    },
    contact: {
        keywords: ['contact', 'contact information', 'phone', 'email', 'address'],
        regex: /(email|phone|mobile|linkedin|github|portfolio)[\s:]+/gi,
        priority: 2,
    },
    summary: {
        keywords: [
            'summary',
            'professional summary',
            'profile',
            'about',
            'about me',
            'objective',
            'career objective',
            'professional profile',
        ],
        regex: /^[\s]*(professional\s+)?(summary|profile|objective|about(\s+me)?)/im,
        priority: 3,
    },
    skills: {
        keywords: [
            'skills',
            'technical skills',
            'core competencies',
            'expertise',
            'technologies',
            'proficiencies',
        ],
        regex: /^[\s]*(technical\s+)?(skills|competencies|expertise|proficiencies)/im,
        priority: 4,
    },
    experience: {
        keywords: [
            'experience',
            'work experience',
            'employment',
            'professional experience',
            'work history',
            'career history',
        ],
        regex: /^[\s]*(work|professional|employment)\s*(experience|history)/im,
        priority: 5,
    },
    education: {
        keywords: ['education', 'academic background', 'qualifications', 'degrees'],
        regex: /^[\s]*education(al\s+background)?/im,
        priority: 6,
    },
    projects: {
        keywords: ['projects', 'portfolio', 'key projects', 'personal projects'],
        regex: /^[\s]*(key\s+|personal\s+|academic\s+)?projects/im,
        priority: 7,
    },
    certifications: {
        keywords: [
            'certifications',
            'certificates',
            'professional certifications',
            'licenses',
        ],
        regex: /^[\s]*(professional\s+)?(certifications?|licenses)/im,
        priority: 8,
    },
    awards: {
        keywords: ['awards', 'honors', 'achievements', 'recognition'],
        regex: /^[\s]*(awards|honors|achievements|recognition)/im,
        priority: 9,
    },
    volunteer: {
        keywords: ['volunteer', 'volunteering', 'community service'],
        regex: /^[\s]*(volunteer(ing)?|community\s+service)/im,
        priority: 10,
    },
};

/**
 * Detect section headings using regex and common patterns
 */
function detectSectionHeadings(text: string): Array<{ name: string; index: number; confidence: number }> {
    const headings: Array<{ name: string; index: number; confidence: number }> = [];
    const lines = text.split('\n');
    let currentIndex = 0;

    lines.forEach((line) => {
        const trimmedLine = line.trim();

        // Check each section pattern
        Object.entries(SECTION_PATTERNS).forEach(([sectionName, pattern]) => {
            // Check regex match
            if (pattern.regex && pattern.regex.test(trimmedLine)) {
                headings.push({
                    name: sectionName,
                    index: currentIndex,
                    confidence: 90,
                });
            } else {
                // Check keyword match
                const lowerLine = trimmedLine.toLowerCase();
                pattern.keywords.forEach((keyword) => {
                    if (lowerLine === keyword || lowerLine === keyword + ':') {
                        headings.push({
                            name: sectionName,
                            index: currentIndex,
                            confidence: 80,
                        });
                    }
                });
            }
        });

        currentIndex += line.length + 1; // +1 for newline
    });

    return headings;
}

/**
 * Extract content between section headings
 */
function extractSectionContent(
    text: string,
    headings: Array<{ name: string; index: number; confidence: number }>
): { [sectionName: string]: DetectedSection } {
    const sections: { [sectionName: string]: DetectedSection } = {};

    // Sort headings by index
    const sortedHeadings = [...headings].sort((a, b) => a.index - b.index);

    sortedHeadings.forEach((heading, idx) => {
        const startIndex = heading.index;
        const endIndex = idx < sortedHeadings.length - 1
            ? sortedHeadings[idx + 1].index
            : text.length;

        const content = text.substring(startIndex, endIndex).trim();

        // Only add if not already exists or has higher confidence
        if (!sections[heading.name] || sections[heading.name].confidence < heading.confidence) {
            sections[heading.name] = {
                name: heading.name,
                content,
                startIndex,
                endIndex,
                confidence: heading.confidence,
                detectionMethod: 'heading',
            };
        }
    });

    return sections;
}

/**
 * Try to extract name from the beginning of the resume
 */
function extractName(text: string): DetectedSection | null {
    const lines = text.split('\n').filter((line) => line.trim().length > 0);

    if (lines.length === 0) return null;

    // First line is often the name
    const firstLine = lines[0].trim();

    // Name heuristics:
    // - 2-5 words
    // - Title case
    // - No special characters (except spaces)
    // - Length 5-50 characters
    const words = firstLine.split(/\s+/);
    const isLikelyName =
        words.length >= 2 &&
        words.length <= 5 &&
        /^[A-Z]/.test(firstLine) &&
        !/[^\w\s\.]/.test(firstLine) &&
        firstLine.length >= 5 &&
        firstLine.length <= 50;

    if (isLikelyName) {
        return {
            name: 'name',
            content: firstLine,
            startIndex: 0,
            endIndex: firstLine.length,
            confidence: 75,
            detectionMethod: 'semantic',
        };
    }

    return null;
}

/**
 * Main section detection function
 */
export function detectResumeSections(resumeText: string): SectionDetectionResult {
    const warnings: string[] = [];
    const sections: { [sectionName: string]: DetectedSection } = {};

    // Detect section headings
    const headings = detectSectionHeadings(resumeText);

    if (headings.length === 0) {
        warnings.push('No clear section headings detected. Resume may have formatting issues.');
    }

    // Extract content for each section
    const detectedSections = extractSectionContent(resumeText, headings);
    Object.assign(sections, detectedSections);

    // Try to extract name if not detected
    if (!sections.name) {
        const nameSection = extractName(resumeText);
        if (nameSection) {
            sections.name = nameSection;
        } else {
            warnings.push('Could not detect candidate name.');
        }
    }

    // Calculate completeness score
    const essentialSections = ['summary', 'skills', 'experience', 'education'];
    const optionalSections = ['projects', 'certifications', 'awards'];

    const essentialFound = essentialSections.filter((s) => sections[s]).length;
    const optionalFound = optionalSections.filter((s) => sections[s]).length;

    const completenessScore = Math.round(
        (essentialFound / essentialSections.length) * 70 +
        (optionalFound / optionalSections.length) * 30
    );

    // Add warnings for missing essential sections
    essentialSections.forEach((section) => {
        if (!sections[section]) {
            warnings.push(`Missing essential section: ${section}`);
        }
    });

    return {
        sections,
        detectedSectionNames: Object.keys(sections),
        completenessScore,
        warnings,
    };
}

/**
 * Get section by name (case-insensitive)
 */
export function getSection(
    detectionResult: SectionDetectionResult,
    sectionName: string
): DetectedSection | null {
    const normalized = sectionName.toLowerCase();
    return detectionResult.sections[normalized] || null;
}

/**
 * Check if resume has all essential sections
 */
export function hasEssentialSections(detectionResult: SectionDetectionResult): boolean {
    const essentialSections = ['summary', 'skills', 'experience', 'education'];
    return essentialSections.every((section) => detectionResult.sections[section]);
}

/**
 * GitHub Portfolio Analyzer
 * Fetches and analyzes GitHub portfolio data using the GitHub REST API
 */

import { Octokit } from 'octokit';

export interface PortfolioAnalysis {
    username: string;
    profileData: {
        name: string | null;
        bio: string | null;
        location: string | null;
        publicRepos: number;
        followers: number;
        following: number;
        createdAt: Date;
    };
    repositoryMetrics: {
        totalRepos: number;
        totalStars: number;
        totalForks: number;
        languageDistribution: { [language: string]: number };
        avgCommitsPerRepo: number;
        lastActiveDate: Date;
    };
    topProjects: Array<{
        name: string;
        description: string | null;
        stars: number;
        forks: number;
        language: string | null;
        lastUpdated: Date;
        hasReadme: boolean;
        readmeLength: number;
        url: string;
    }>;
    portfolioScore: number;
    insights: {
        activityScore: number;
        qualityScore: number;
        diversityScore: number;
        documentationScore: number;
        consistencyScore: number;
    };
}

/**
 * Extract GitHub username from various URL formats
 */
export function extractGitHubUsername(input: string): string | null {
    // Remove whitespace
    input = input.trim();

    // Direct username
    if (!input.includes('/') && !input.includes('.')) {
        return input;
    }

    // GitHub URL patterns
    const patterns = [
        /github\.com\/([^\/\?#]+)/i,
        /^@?([a-zA-Z0-9](?:[a-zA-Z0-9]|-(?=[a-zA-Z0-9])){0,38})$/,
    ];

    for (const pattern of patterns) {
        const match = input.match(pattern);
        if (match && match[1]) {
            return match[1];
        }
    }

    return null;
}

/**
 * Analyze GitHub portfolio
 */
import { CareerStage } from '@/types/career-stage';

/**
 * Portfolio Scoring Weights by Career Stage
 */
const PORTFOLIO_WEIGHTS: Record<CareerStage, {
    activity: number;
    quality: number;
    diversity: number;
    documentation: number;
    consistency: number;
}> = {
    // Students/Freshers: Value learning, experimentation, and communication
    student: { activity: 0.35, diversity: 0.25, documentation: 0.20, quality: 0.15, consistency: 0.05 },
    fresher: { activity: 0.30, diversity: 0.25, documentation: 0.20, quality: 0.15, consistency: 0.10 },

    // Juniors: Balance shifting towards quality and consistency
    junior: { quality: 0.25, consistency: 0.20, activity: 0.25, documentation: 0.15, diversity: 0.15 },

    // Mid/Senior: Value production quality, maintenance, and impact
    'mid-level': { quality: 0.35, consistency: 0.25, activity: 0.15, documentation: 0.15, diversity: 0.10 },
    senior: { quality: 0.40, consistency: 0.30, documentation: 0.15, activity: 0.10, diversity: 0.05 },
};

/**
 * Analyze GitHub portfolio
 */
export async function analyzeGitHubPortfolio(
    usernameOrUrl: string,
    careerStage: CareerStage = 'mid-level', // Default if unknown
    githubToken?: string
): Promise<PortfolioAnalysis> {
    const username = extractGitHubUsername(usernameOrUrl);

    if (!username) {
        throw new Error('Invalid GitHub username or URL');
    }

    // Initialize Octokit
    const octokit = new Octokit({
        auth: githubToken, // Optional: increases rate limit from 60 to 5000/hour
    });

    try {
        // Fetch user profile
        const { data: user } = await octokit.rest.users.getByUsername({
            username,
        });

        // Fetch repositories
        const { data: repos } = await octokit.rest.repos.listForUser({
            username,
            sort: 'updated',
            per_page: 100,
        });

        // Calculate language distribution
        const languageDistribution: { [language: string]: number } = {};
        let totalStars = 0;
        let totalForks = 0;
        let totalCommits = 0;
        let reposWithCommits = 0;
        let lastActiveDate = new Date(0);

        // Analyze each repository
        const repoAnalysis = await Promise.all(
            repos.slice(0, 20).map(async (repo) => {
                // Get languages
                const { data: languages } = await octokit.rest.repos.listLanguages({
                    owner: username,
                    repo: repo.name,
                });

                // Aggregate language data
                Object.entries(languages).forEach(([lang, bytes]) => {
                    languageDistribution[lang] = (languageDistribution[lang] || 0) + bytes;
                });

                // Get README
                let hasReadme = false;
                let readmeLength = 0;
                try {
                    const { data: readme } = await octokit.rest.repos.getReadme({
                        owner: username,
                        repo: repo.name,
                    });
                    hasReadme = true;
                    readmeLength = Buffer.from(readme.content, 'base64').toString().length;
                } catch {
                    // No README
                }

                // Get commit count (last 12 months)
                try {
                    const { data: commits } = await octokit.rest.repos.listCommits({
                        owner: username,
                        repo: repo.name,
                        per_page: 100,
                        since: new Date(Date.now() - 365 * 24 * 60 * 60 * 1000).toISOString(),
                    });
                    totalCommits += commits.length;
                    reposWithCommits++;
                } catch {
                    // Unable to fetch commits (empty repo or private)
                }

                // Track activity
                const updatedAt = new Date(repo.updated_at);
                if (updatedAt > lastActiveDate) {
                    lastActiveDate = updatedAt;
                }

                totalStars += repo.stargazers_count || 0;
                totalForks += repo.forks_count || 0;

                return {
                    name: repo.name,
                    description: repo.description,
                    stars: repo.stargazers_count || 0,
                    forks: repo.forks_count || 0,
                    language: repo.language,
                    lastUpdated: new Date(repo.updated_at),
                    hasReadme,
                    readmeLength,
                    url: repo.html_url,
                };
            })
        );

        // Sort by stars to get top projects
        const topProjects = repoAnalysis
            .sort((a, b) => b.stars - a.stars)
            .slice(0, 5);

        // Calculate scores
        const avgCommitsPerRepo = reposWithCommits > 0 ? totalCommits / reposWithCommits : 0;

        // Activity Score (0-100): Based on recent commits and updates
        const daysSinceLastActivity = Math.floor(
            (Date.now() - lastActiveDate.getTime()) / (1000 * 60 * 60 * 24)
        );
        const activityScore = Math.max(0, 100 - daysSinceLastActivity * 2);

        // Quality Score (0-100): Based on stars and forks
        const avgStarsPerRepo = repos.length > 0 ? totalStars / repos.length : 0;
        const qualityScore = Math.min(100, avgStarsPerRepo * 10 + (totalForks > 10 ? 20 : 0));

        // Diversity Score (0-100): Based on language variety
        const languageCount = Object.keys(languageDistribution).length;
        const diversityScore = Math.min(100, languageCount * 15);

        // Documentation Score (0-100): Based on README presence and quality
        const reposWithReadme = repoAnalysis.filter((r) => r.hasReadme).length;
        const avgReadmeLength = repoAnalysis.reduce((sum, r) => sum + r.readmeLength, 0) / repoAnalysis.length;
        const documentationScore = Math.min(
            100,
            (reposWithReadme / repoAnalysis.length) * 50 + Math.min(50, avgReadmeLength / 10)
        );

        // Consistency Score (0-100): Based on regular commits
        const consistencyScore = Math.min(100, avgCommitsPerRepo * 5);

        // Get weights for career stage
        const weights = PORTFOLIO_WEIGHTS[careerStage];

        // Overall Portfolio Score (weighted average based on stage)
        const portfolioScore = Math.round(
            activityScore * weights.activity +
            qualityScore * weights.quality +
            diversityScore * weights.diversity +
            documentationScore * weights.documentation +
            consistencyScore * weights.consistency
        );

        return {
            username,
            profileData: {
                name: user.name,
                bio: user.bio,
                location: user.location,
                publicRepos: user.public_repos,
                followers: user.followers,
                following: user.following,
                createdAt: new Date(user.created_at),
            },
            repositoryMetrics: {
                totalRepos: repos.length,
                totalStars,
                totalForks,
                languageDistribution,
                avgCommitsPerRepo: Math.round(avgCommitsPerRepo),
                lastActiveDate,
            },
            topProjects,
            portfolioScore,
            insights: {
                activityScore: Math.round(activityScore),
                qualityScore: Math.round(qualityScore),
                diversityScore: Math.round(diversityScore),
                documentationScore: Math.round(documentationScore),
                consistencyScore: Math.round(consistencyScore),
            },
        };
    } catch (error: unknown) {
        const err = error as { status?: number; message?: string };
        if (err.status === 404) {
            throw new Error(`GitHub user "${username}" not found`);
        } else if (err.status === 403) {
            throw new Error('GitHub API rate limit exceeded. Please try again later or provide a GitHub token.');
        } else {
            throw new Error(`Failed to analyze GitHub portfolio: ${err.message || 'Unknown error'}`);
        }
    }
}

/**
 * Validate GitHub username format
 */
export function validateGitHubUsername(username: string): { valid: boolean; error?: string } {
    const extracted = extractGitHubUsername(username);

    if (!extracted) {
        return {
            valid: false,
            error: 'Invalid GitHub username or URL format',
        };
    }

    // GitHub username rules: 1-39 characters, alphanumeric or hyphens, cannot start/end with hyphen
    if (!/^[a-zA-Z0-9](?:[a-zA-Z0-9]|-(?=[a-zA-Z0-9])){0,38}$/.test(extracted)) {
        return {
            valid: false,
            error: 'Invalid GitHub username format',
        };
    }

    return { valid: true };
}

/**
 * Central Resume Parser
 * Orchestrates parsing of PDF, DOCX, and TXT files
 */

import { extractTextFromPDF, validatePDFFile, type PDFParseResult } from './pdfParser';
import { extractTextFromDOCX, validateDOCXFile, type DOCXParseResult } from './docxParser';

export interface ParsedResume {
    rawText: string;
    metadata: {
        fileName: string;
        fileSize: number;
        fileType: string;
        parseTimestamp: Date;
        pageCount?: number;
        parsingMethod: 'pdf' | 'docx' | 'txt';
    };
    parsingConfidence: number;
    warnings: string[];
}

/**
 * Extract text from a plain text file
 */
async function extractTextFromTXT(file: File): Promise<string> {
    return await file.text();
}

/**
 * Validate TXT file
 */
function validateTXTFile(file: File): { valid: boolean; error?: string } {
    if (!file.type.includes('text/plain') && !file.name.endsWith('.txt')) {
        return { valid: false, error: 'File must be a text file (.txt)' };
    }

    const maxSize = 2 * 1024 * 1024; // 2MB
    if (file.size > maxSize) {
        return { valid: false, error: 'Text file must be smaller than 2MB' };
    }

    return { valid: true };
}

/**
 * Main resume parser function
 * Automatically detects file type and uses appropriate parser
 */
export async function parseResume(file: File): Promise<ParsedResume> {
    const fileName = file.name;
    const fileSize = file.size;
    const parseTimestamp = new Date();

    let rawText: string;
    let parsingMethod: 'pdf' | 'docx' | 'txt';
    let parsingConfidence: number;
    let warnings: string[] = [];
    let pageCount: number | undefined;

    // Detect file type and parse accordingly
    if (file.type === 'application/pdf' || fileName.endsWith('.pdf')) {
        // PDF parsing
        const validation = validatePDFFile(file);
        if (!validation.valid) {
            throw new Error(validation.error);
        }

        const pdfResult = await extractTextFromPDF(file);
        rawText = pdfResult.text;
        pageCount = pdfResult.pageCount;
        parsingMethod = 'pdf';

        // Calculate confidence based on text extraction quality
        if (rawText.length < 100) {
            parsingConfidence = 40;
            warnings.push('Very little text extracted. PDF may contain images or scanned content.');
        } else if (rawText.length < 500) {
            parsingConfidence = 70;
            warnings.push('Limited text extracted. Some content may be missing.');
        } else {
            parsingConfidence = 95;
        }

    } else if (
        file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' ||
        file.type === 'application/msword' ||
        fileName.endsWith('.docx') ||
        fileName.endsWith('.doc')
    ) {
        // DOCX parsing
        const validation = validateDOCXFile(file);
        if (!validation.valid) {
            throw new Error(validation.error);
        }

        const docxResult = await extractTextFromDOCX(file);
        rawText = docxResult.text;
        parsingMethod = 'docx';

        if (docxResult.messages.length > 0) {
            warnings.push(...docxResult.messages);
        }

        if (rawText.length < 100) {
            parsingConfidence = 50;
            warnings.push('Very little text extracted from document.');
        } else if (docxResult.messages.length > 3) {
            parsingConfidence = 75;
        } else {
            parsingConfidence = 90;
        }

    } else if (file.type.includes('text/plain') || fileName.endsWith('.txt')) {
        // TXT parsing
        const validation = validateTXTFile(file);
        if (!validation.valid) {
            throw new Error(validation.error);
        }

        rawText = await extractTextFromTXT(file);
        parsingMethod = 'txt';
        parsingConfidence = 85;

    } else {
        throw new Error('Unsupported file type. Please upload a PDF, DOCX, or TXT file.');
    }

    // Additional validation
    if (rawText.trim().length === 0) {
        throw new Error('No text could be extracted from the file. The file may be empty or corrupted.');
    }

    return {
        rawText,
        metadata: {
            fileName,
            fileSize,
            fileType: file.type,
            parseTimestamp,
            pageCount,
            parsingMethod,
        },
        parsingConfidence,
        warnings,
    };
}

/**
 * Validate file before attempting to parse
 */
export function validateResumeFile(file: File): { valid: boolean; error?: string } {
    // Check file type
    const isPDF = file.type === 'application/pdf' || file.name.endsWith('.pdf');
    const isDOCX = file.type === 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' ||
        file.type === 'application/msword' ||
        file.name.endsWith('.docx') ||
        file.name.endsWith('.doc');
    const isTXT = file.type.includes('text/plain') || file.name.endsWith('.txt');

    if (!isPDF && !isDOCX && !isTXT) {
        return {
            valid: false,
            error: 'Invalid file type. Please upload a PDF, Word document (.docx), or text file (.txt).',
        };
    }

    // Validate based on type
    if (isPDF) return validatePDFFile(file);
    if (isDOCX) return validateDOCXFile(file);
    if (isTXT) return validateTXTFile(file);

    return { valid: true };
}

import jsPDF from "jspdf";
import autoTable from "jspdf-autotable";
import type { AnalysisResult } from "./types";

export function generatePDFReport(data: AnalysisResult) {
  const doc = new jsPDF();
  const pageWidth = doc.internal.pageSize.getWidth();
  let y = 20;

  const addSection = (title: string) => {
    if (y > 250) {
      doc.addPage();
      y = 20;
    }
    doc.setFontSize(14);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(20, 100, 100);
    doc.text(title, 14, y);
    y += 8;
    doc.setDrawColor(20, 100, 100);
    doc.line(14, y, pageWidth - 14, y);
    y += 6;
  };

  // Header
  doc.setFillColor(15, 80, 85);
  doc.rect(0, 0, pageWidth, 40, "F");
  doc.setFontSize(22);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(255, 255, 255);
  doc.text("Resume & Portfolio Optimization Report", pageWidth / 2, 18, { align: "center" });
  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.text("Generated by Resume Optimizer", pageWidth / 2, 28, { align: "center" });
  doc.text(new Date().toLocaleDateString("en-IN", { year: "numeric", month: "long", day: "numeric" }), pageWidth / 2, 34, { align: "center" });
  y = 50;

  // ATS Score
  addSection("ATS Compatibility Score");
  doc.setFontSize(28);
  doc.setFont("helvetica", "bold");
  const scoreColor = data.atsScore.overall >= 80 ? [34, 197, 94] : data.atsScore.overall >= 60 ? [34, 197, 94] : data.atsScore.overall >= 40 ? [234, 179, 8] : [239, 68, 68];
  doc.setTextColor(scoreColor[0], scoreColor[1], scoreColor[2]);
  doc.text(`${data.atsScore.overall}/100`, 14, y + 2);

  doc.setFontSize(9);
  doc.setTextColor(80, 80, 80);
  doc.setFont("helvetica", "normal");
  const breakdownLines = data.atsScore.weightBreakdown.map(
    (wb) => `${wb.factor} (${wb.weight}%): ${wb.score.toFixed(1)}/${wb.maxScore}`
  );
  breakdownLines.forEach((line, i) => {
    doc.text(`• ${line}`, 60, y - 6 + i * 5);
  });
  y += Math.max(12, breakdownLines.length * 5 + 4);

  // Tips
  doc.setFontSize(9);
  data.atsScore.details.forEach((tip) => {
    doc.text(`💡 ${tip}`, 14, y);
    y += 5;
  });
  y += 6;

  // Job Match
  addSection("Job Match Analysis");
  doc.setFontSize(11);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(40, 40, 40);
  doc.text(`Match Percentage: ${data.jobMatch.matchPercentage}%`, 14, y);
  y += 7;
  doc.setFont("helvetica", "normal");
  doc.setFontSize(9);
  doc.text(`Missing Skills: ${data.jobMatch.missingSkills.join(", ")}`, 14, y);
  y += 10;

  // Keyword Gap Table
  addSection("Keyword Gap Analysis");
  autoTable(doc, {
    startY: y,
    head: [["Keyword", "Importance", "JD Freq.", "Resume Count", "Type", "Placement"]],
    body: data.keywordGaps.map((g) => [
      g.keyword,
      g.importance.toUpperCase(),
      `${g.jdFrequency}×`,
      `${g.resumeOccurrences}×`,
      g.required ? "Required" : "Optional",
      g.suggestedPlacement,
    ]),
    styles: { fontSize: 8, cellPadding: 2 },
    headStyles: { fillColor: [20, 100, 100], fontSize: 8 },
    alternateRowStyles: { fillColor: [245, 245, 245] },
    margin: { left: 14, right: 14 },
  });
  y = (doc as any).lastAutoTable.finalY + 10;

  // Section Analysis
  if (y > 230) { doc.addPage(); y = 20; }
  addSection("Section Analysis");
  data.sectionAnalyses.forEach((s) => {
    if (y > 260) { doc.addPage(); y = 20; }
    doc.setFontSize(10);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(40, 40, 40);
    doc.text(`${s.name}: ${s.strengthRating}/100`, 14, y);
    y += 5;
    doc.setFont("helvetica", "normal");
    doc.setFontSize(8);
    doc.setTextColor(80, 80, 80);
    s.weaknesses.forEach((w) => {
      doc.text(`  ⚠ ${w}`, 14, y);
      y += 4;
    });
    doc.text(`  💡 ${s.rewriteSuggestion}`, 14, y);
    y += 7;
  });

  // Portfolio
  if (y > 230) { doc.addPage(); y = 20; }
  addSection("Portfolio Score");
  doc.setFontSize(11);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(40, 40, 40);
  doc.text(`Overall Rating: ${data.portfolioAnalysis.overallRating}/100`, 14, y);
  y += 7;

  autoTable(doc, {
    startY: y,
    head: [["Metric", "Raw Value", "Weight", "Score"]],
    body: data.portfolioAnalysis.scoringInputs.map((i) => [
      i.metric,
      i.rawValue,
      `${i.weight}%`,
      `${i.score.toFixed(1)}/${i.maxScore}`,
    ]),
    styles: { fontSize: 8, cellPadding: 2 },
    headStyles: { fillColor: [20, 100, 100], fontSize: 8 },
    margin: { left: 14, right: 14 },
  });
  y = (doc as any).lastAutoTable.finalY + 10;

  // Action Plan
  if (y > 200) { doc.addPage(); y = 20; }
  addSection("Action Plan");
  autoTable(doc, {
    startY: y,
    head: [["#", "Task", "Priority", "Effort", "Impact", "Reason"]],
    body: data.actionItems.map((item, i) => [
      `${i + 1}`,
      item.title,
      item.priorityLevel.toUpperCase(),
      item.estimatedEffort,
      `${item.recruiterImpact}/10`,
      item.triggerReason.substring(0, 60) + (item.triggerReason.length > 60 ? "..." : ""),
    ]),
    styles: { fontSize: 7, cellPadding: 2 },
    headStyles: { fillColor: [20, 100, 100], fontSize: 7 },
    columnStyles: { 0: { cellWidth: 8 }, 5: { cellWidth: 45 } },
    margin: { left: 14, right: 14 },
  });

  // Watermark on each page
  const pageCount = doc.getNumberOfPages();
  for (let i = 1; i <= pageCount; i++) {
    doc.setPage(i);
    doc.setFontSize(8);
    doc.setTextColor(160, 160, 160);
    doc.text("Generated by Resume Optimizer", pageWidth / 2, doc.internal.pageSize.getHeight() - 8, { align: "center" });
    doc.text(`Page ${i} of ${pageCount}`, pageWidth - 14, doc.internal.pageSize.getHeight() - 8, { align: "right" });
  }

  doc.save("resume-analysis-report.pdf");
}

